const d = $input.first().json;
let score = 0;
const components = {};

// 1. 20% Value Advantage (25 pts) - Sam's Club requirement
components.valueAdvantage = d.has20PctValue === 'yes' ? 25 : 10;
score += components.valueAdvantage;

// 2. Pricing & Margin Fit (25 pts)
let priceFit = 0;
if (d.pricingWorks === 'yes') priceFit += 12;
if (d.canBreakEven === 'yes') priceFit += 8;
if (d.canProvideCOGS === 'yes') priceFit += 5;
components.pricingFit = priceFit;
score += components.pricingFit;

// 3. Operational Readiness (20 pts)
let ops = 0;
if (d.consignmentReady === 'yes') ops += 8;
if (d.multiClub === 'yes') ops += 7;
if (d.hasInsurance === 'yes') ops += 5;
components.operationalReadiness = ops;
score += components.operationalReadiness;

// 4. Product Differentiation (20 pts)
const diffLen = (d.differentiation || '').length + (d.memberValue || '').length;
components.differentiation = diffLen > 400 ? 20 : diffLen > 200 ? 15 : diffLen > 80 ? 10 : 5;
score += components.differentiation;

// 5. Compliance Readiness (10 pts)
components.compliance = d.complianceScore ? Math.round(d.complianceScore * 0.1) : 5;
score += components.compliance;

score = Math.min(score, 100);

return [{ json: {
  ...d,
  readinessScore: score,
  readinessComponents: components,
  readinessComputedAt: new Date().toISOString(),
  phase: 3,
  readinessPass: score >= 60
} }];
